import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // === Simplest cases ===
  it.todo("empty item list → premium 5 G (only the processing fee)");

  // === Base premiums for main items (with processing fee, no other modifiers, no customer history) ===
  it.todo("single sword (steel, enchantment 0, not cursed), newcomer's first contract → 100 + 10 first + 5 fee = 115 G");
  it.todo("single amulet base premium 60 G applied correctly in newcomer first contract scenario → 60 + 6 first + 5 fee = 71 G");
  it.todo("single staff base premium 80 G in newcomer first contract → 80 + 8 first + 5 fee = 93 G");
  it.todo("single potion base premium 40 G in newcomer first contract → 40 + 4 first + 5 fee = 49 G");

  // === Components block-of-3 rule ===
  it.todo("2 runes → 50 G base premium (no block)");
  it.todo("3 runes → 60 G base premium (block applies)");
  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
  it.todo("7 runes → 175 G base premium (no block possible from 7)");

  // === Alike components clarification ===
  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");

  // === Modifier scope on multi-item policies ===
  it.todo("cursed sword + plain amulet for newcomer first contract → 210 G base + first/fee");

  // === Modifier thresholds ===
  it.todo("customer with exactly 2 years with MHPCO → loyalty discount applies");
  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
  it.todo("sword with exactly enchantment 5 AND cursed → both surcharges apply");
  it.todo("sword with enchantment 4 → no high-enchantment surcharge");

  // === Rounding (in MHPCO's favor — premium rounds up) ===
  it.todo("premium calculation yielding 197.5 G → final premium 198 G");

  // === Edge case errors for quote ===
  it.todo("quote with unknown item type → throws/rejects");

  // === Integration examples ===
  it.todo("newcomer with a cursed sword (enchantment 3) → premium 165 G");
  it.todo("long-standing customer's second contract: cursed sword enchantment 7 → premium 160 G");

  // === Claim processing — standard reimbursement ===
  it.todo("regular sword damage 500 G → payout 400 G (full minus 100 G deductible)");
  it.todo("rune damage 200 G → payout 100 G (full minus 100 G deductible)");

  // === Claim — special clauses ===
  it.todo("dragon-material sword enchantment 8 damage 1000 G → payout 400 G (high-ench 50% then deductible)");
  it.todo("dragon-material sword enchantment 9 damage 1000 G → payout 400 G (50% wins, then deductible)");
  it.todo("dragon-material sword enchantment 5 damage 800 G → payout 700 G (full minus deductible)");
  it.todo("steel sword enchantment 9 damage 1000 G → payout 400 G (50% then deductible)");

  // === Deductible per damage event ===
  it.todo("dragon attack damaging sword (500) and amulet (300) → payout 600 G (deductible per item)");

  // === Multiple items of the same type ===
  it.todo("policy with two swords → insurance sum 2000 G, cap 4000 G; both damaged → separate deductibles");
  it.todo("damages array contains more entries of a type than insured → claim rejected (non-zero exit)");

  // === Cap exhaustion ===
  it.todo("sword + amulet → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword → cap 2000 G (based on unmodified insurance value)");
  it.todo("sword + 3 runes → insurance sum 1750 G (block discount does not affect insurance sum)");
  it.todo("sword cap 2000 G, two successive 1500 G claims → first payout 1400 G (cap 600), second payout 600 G (cap 0)");

  // === Payout rounding (in MHPCO's favor — payout rounds down) ===
  it.todo("payout calculation yielding 350.5 G → final payout 350 G");

  // === Claim error cases ===
  it.todo("claim references damage entry for item not in policy → rejected");
  it.todo("claim contains damage entry with negative amount → rejected");
});

