export type Item = {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
};

export type QuoteStep = {
  op: "quote";
  items: Item[];
};

export type Step = QuoteStep;

export type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
};

export type QuoteResult = { premium: number };
export type StepResult = QuoteResult;

export type ScenarioResult = {
  results: StepResult[];
};

const PROCESSING_FEE = 5;
const FIRST_CONTRACT_SURCHARGE_RATE = 0.1;
const BLOCK_OF_THREE_DISCOUNT = 15;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const blockOfThreeDiscount = (count: number): number =>
  count === 3 ? BLOCK_OF_THREE_DISCOUNT : 0;

const sumBasePremiums = (items: Item[]): number => {
  const ungroupedTotal = items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
  const runeCount = items.filter((i) => i.type === "rune").length;
  return ungroupedTotal - blockOfThreeDiscount(runeCount);
};

const quote = (step: QuoteStep): QuoteResult => {
  const itemsBase = sumBasePremiums(step.items);
  const firstContractSurcharge = itemsBase * FIRST_CONTRACT_SURCHARGE_RATE;
  const premium = itemsBase + firstContractSurcharge + PROCESSING_FEE;
  return { premium };
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const results = scenario.steps.map(quote);
  return { results };
};

