export type Item = {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
};

export type QuoteStep = {
  op: "quote";
  items: Item[];
};

export type Step = QuoteStep;

export type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
};

export type QuoteResult = { premium: number };
export type StepResult = QuoteResult;

export type ScenarioResult = {
  results: StepResult[];
};

const PROCESSING_FEE = 5;
const FIRST_CONTRACT_SURCHARGE_RATE = 0.1;
const BLOCK_OF_THREE_DISCOUNT = 15;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const blockOfThreeDiscount = (alikeComponentCount: number): number =>
  alikeComponentCount === 3 ? BLOCK_OF_THREE_DISCOUNT : 0;

const COMPONENT_TYPES = ["rune", "moonstone"];

const countItemsOfType = (items: Item[], type: string): number =>
  items.filter((item) => item.type === type).length;

const CURSE_SURCHARGE_RATE = 0.5;

const sumItemSpecificSurcharges = (items: Item[]): number =>
  items.reduce((sum, item) => {
    const base = BASE_PREMIUM[item.type];
    const curse = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
    return sum + curse;
  }, 0);

const calculateBasePremium = (items: Item[]): number => {
  const subtotal = items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
  const totalDiscount = COMPONENT_TYPES.reduce(
    (sum, type) => sum + blockOfThreeDiscount(countItemsOfType(items, type)),
    0,
  );
  return subtotal - totalDiscount;
};

const sumBasePremiums = (items: Item[]): number =>
  items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);

const quote = (step: QuoteStep): QuoteResult => {
  const itemsWithModifiers = calculateBasePremium(step.items);
  const firstInsurance = sumBasePremiums(step.items) * FIRST_CONTRACT_SURCHARGE_RATE;
  const premium = Math.ceil(itemsWithModifiers + firstInsurance + PROCESSING_FEE);
  return { premium };
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const results = scenario.steps.map(quote);
  return { results };
};

