export type Item = {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
};

export type QuoteStep = {
  op: "quote";
  items: Item[];
};

export type Step = QuoteStep;

export type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
};

export type QuoteResult = { premium: number };
export type StepResult = QuoteResult;

export type ScenarioResult = {
  results: StepResult[];
};

const PROCESSING_FEE = 5;
const FIRST_CONTRACT_SURCHARGE_RATE = 0.1;
const BLOCK_OF_THREE_DISCOUNT = 15;
const CURSE_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const LOYALTY_DISCOUNT_RATE = 0.2;
const LOYALTY_YEARS_THRESHOLD = 2;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = ["rune", "moonstone"];

const blockOfThreeDiscount = (alikeComponentCount: number): number =>
  alikeComponentCount === 3 ? BLOCK_OF_THREE_DISCOUNT : 0;

const countItemsOfType = (items: Item[], type: string): number =>
  items.filter((item) => item.type === type).length;

const isCursed = (item: Item): boolean => item.cursed === true;
const isHighlyEnchanted = (item: Item): boolean =>
  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;

const ITEM_SURCHARGE_RATES: ReadonlyArray<{
  applies: (item: Item) => boolean;
  rate: number;
}> = [
  { applies: isCursed, rate: CURSE_SURCHARGE_RATE },
  { applies: isHighlyEnchanted, rate: HIGH_ENCHANTMENT_SURCHARGE_RATE },
];

const surchargesForItem = (item: Item): number => {
  const base = BASE_PREMIUM[item.type];
  return ITEM_SURCHARGE_RATES.reduce(
    (sum, { applies, rate }) => sum + (applies(item) ? base * rate : 0),
    0,
  );
};

const sumItemSpecificSurcharges = (items: Item[]): number =>
  items.reduce((sum, item) => sum + surchargesForItem(item), 0);

const calculateBasePremium = (items: Item[]): number => {
  const subtotal = items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
  const totalDiscount = COMPONENT_TYPES.reduce(
    (sum, type) => sum + blockOfThreeDiscount(countItemsOfType(items, type)),
    0,
  );
  return subtotal - totalDiscount;
};

const firstContractSurcharge = (basePremium: number): number =>
  basePremium * FIRST_CONTRACT_SURCHARGE_RATE;

const qualifiesForLoyaltyDiscount = (yearsWithMHPCO: number): boolean =>
  yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;

const loyaltyDiscount = (basePremium: number, yearsWithMHPCO: number): number =>
  qualifiesForLoyaltyDiscount(yearsWithMHPCO) ? basePremium * LOYALTY_DISCOUNT_RATE : 0;

const quote = (step: QuoteStep, customer: Scenario["customer"]): QuoteResult => {
  const basePremium = calculateBasePremium(step.items);
  const itemSurcharges = sumItemSpecificSurcharges(step.items);
  const premium = Math.ceil(
    basePremium +
      itemSurcharges +
      firstContractSurcharge(basePremium) -
      loyaltyDiscount(basePremium, customer.yearsWithMHPCO) +
      PROCESSING_FEE,
  );
  return { premium };
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const results = scenario.steps.map((step) => quote(step, scenario.customer));
  return { results };
};

