type Policy = { items: Item[]; cap: number };

const insuranceSumOf = (items: Item[]): number =>
  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);

const claim = (step: ClaimStep, policy: Policy): { result: ClaimResult; newCap: number } => {
  const payout = step.incident.damages.reduce(
    (sum, dmg) => sum + Math.max(0, dmg.amount - DEDUCTIBLE),
    0,
  );
  const cappedPayout = Math.min(payout, policy.cap);
  const newCap = policy.cap - cappedPayout;
  return { result: { payout: Math.floor(cappedPayout), remainingCap: newCap }, newCap };
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const policies: Policy[] = [];
  let priorQuoteCount = 0;
  const results: StepResult[] = scenario.steps.map((step) => {
    if (step.op === "quote") {
      const isFollowUp = priorQuoteCount > 0;
      priorQuoteCount += 1;
      const result = quote(step, scenario.customer, isFollowUp);
      policies.push({ items: step.items, cap: insuranceSumOf(step.items) * CAP_MULTIPLIER });
      return result;
    }
    const policy = policies[step.policy];
    const { result, newCap } = claim(step, policy);
    policy.cap = newCap;
    return result;
  });
  return { results };
};

