  const reimbursable =
    insuredItem && (insuredItem.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
      ? damage.amount * HIGH_ENCHANTMENT_PAYOUT_RATE
      : damage.amount;
